arguments.prompt:
You are implementing a Blazor Web App for a logistics company that tracks shipments. The project is already scaffolded at `/tmp/sv-2121427f148047c99a79212d55244287/ShipmentTracker/` using `dotnet new blazor -int Auto -ai -au Individual`.

## Architecture
- **Interactive Auto, Global** mode — components run on Server first visit, then WebAssembly on subsequent visits.
- Two projects: `ShipmentTracker` (server) and `ShipmentTracker.Client` (WebAssembly client).
- All interactive components MUST go in the `.Client` project.
- Data access from interactive components must go through HTTP APIs (not direct DbContext).
- Both Program.cs files must register matching services.

## What to implement

### 1. Shared Models (in `.Client` project since both sides need them)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Exception
}
```

### 2. Service Interface (in `.Client` project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Client-side HTTP Implementation (in `.Client` project)

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 4. Server-side Entity & DbContext

Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();
}
```

### 5. Server-side Service Implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .OrderByDescending(s => s.ShippedDate)
            .ToListAsync();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id) ?? throw new InvalidOperationException("Shipment not found");
        shipment.Status = status;
        if (status == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return shipment;
    }
}
```

### 6. API Endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.AspNetCore.Mvc;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).AllowAnonymous();

        group.MapGet("/customer/{email}", async (string email, IShipmentService service) =>
            Results.Ok(await service.GetShipmentsByCustomerAsync(email)));

        group.MapPut("/{id}/status", async (int id, [FromBody] ShipmentStatus status, IShipmentService service) =>
        {
            var shipment = await service.UpdateShipmentStatusAsync(id, status);
            return Results.Ok(shipment);
        });
    }
}
