using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
