@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipment Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
