                        <span>@s.TrackingNumber</span>
                        <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="card-text"><strong>@s.Description</strong></p>
                        <p class="card-text">@s.Origin → @s.Destination</p>
                        <p class="card-text">
                            <small class="text-muted">
                                Est. Delivery: @s.EstimatedDelivery.ToString("MMM dd, yyyy")
                                @if (s.ActualDelivery.HasValue)
                                {
                                    <br/>@:Delivered: @s.ActualDelivery.Value.ToString("MMM dd, yyyy")
                                }
                            </small>
                        </p>
                        <a href="track/@s.TrackingNumber" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Shipment>? shipments;
