    {
        await LoadMyShipments();
    }

    private async Task LoadMyShipments()
    {
        isLoading = true;
        try
        {
            var authState = await AuthStateProvider.GetAuthenticationStateAsync();
            var email = authState.User.Identity?.Name ?? string.Empty;
            shipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
