        Showing @FilteredShipments.Count() of @shipments.Count shipments
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;
    private bool isLoading;
    private int? openDropdownId;

    private IEnumerable<Shipment> FilteredShipments => shipments?
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus)
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleDropdown(int id)
    {
        openDropdownId = openDropdownId == id ? null : id;
    }

    private async Task UpdateStatus(int id, ShipmentStatus newStatus)
    {
        openDropdownId = null;
        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
        await LoadShipments();
    }

    private static ShipmentStatus[] GetNextStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Exception],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Exception],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Exception],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Exception],
        ShipmentStatus.Exception => [ShipmentStatus.InTransit, ShipmentStatus.Pending],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}

