#### Create `ShipmentTracker.Client/Pages/Track.razor` (public, no auth required):
```razor
@page "/track"
@page "/track/{TrackingNumber}"
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-2026-001)"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isLoading">
                @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@lastSearched</strong>".
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Description:</strong> @shipment.Description</p>
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</p>
                    }
                </div>
            </div>

            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isLoading;
    private bool searched;
    private string lastSearched = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task HandleKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;
        isLoading = true;
        lastSearched = searchTrackingNumber.Trim();
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        }
        catch
        {
            shipment = null;
        }
        searched = true;
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };
}
```

#### Create `ShipmentTracker.Client/Pages/Shipments.razor` (dispatcher dashboard, requires auth):
```razor
@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipment Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-secondary" @onclick="LoadShipments" disabled="@isLoading">
            @if (isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Refresh
        </button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Description</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><a href="track/@s.TrackingNumber">@s.TrackingNumber</a></td>
                        <td>@s.Description</td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered)
                            {
                                <div class="dropdown">
                                    <button class="btn btn-sm btn-outline-primary dropdown-toggle"
                                            type="button" @onclick="() => ToggleDropdown(s.Id)">
                                        Update
                                    </button>
                                    @if (openDropdownId == s.Id)
                                    {
                                        <div class="dropdown-menu show">
                                            @foreach (var status in GetNextStatuses(s.Status))
                                            {
                                                <button class="dropdown-item" @onclick="() => UpdateStatus(s.Id, status)">
                                                    @status
                                                </button>
                                            }
                                        </div>
                                    }
                                </div>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <div class="text-muted">
        Showing @FilteredShipments.Count() of @shipments.Count shipments
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;
    private bool isLoading;
    private int? openDropdownId;

    private IEnumerable<Shipment> FilteredShipments => shipments?
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus)
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleDropdown(int id)
    {
        openDropdownId = openDropdownId == id ? null : id;
    }

    private async Task UpdateStatus(int id, ShipmentStatus newStatus)
    {
        openDropdownId = null;
        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
        await LoadShipments();
    }

    private static ShipmentStatus[] GetNextStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Exception],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Exception],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Exception],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Exception],
        ShipmentStatus.Exception => [ShipmentStatus.InTransit, ShipmentStatus.Pending],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}
```

